const ticket = $input.first().json.body?.record;
if (!ticket) return [];
return { json: ticket };

const ticket = $('Extract Ticket').first().json;
const order = $input.first()?.json || {};

// On fusionne le ticket original et les infos de la commande trouvée en BDD
return { 
  json: { 
    ...ticket, 
    order_details: order 
  } 
};

const ticket = $('Extract Ticket').first().json;
const aiOutput = $input.first().json;

// Gère tous les formats de sortie (OpenAI, Anthropic, DUST, Simplify Output On/Off)
const raw = aiOutput.text 
  || aiOutput.message?.content 
  || aiOutput.agentMessage 
  || aiOutput.output?.[0]?.content?.[0]?.text 
  || aiOutput.answer 
  || aiOutput.message 
  || '{}';

let parsed;
try {
  const cleanRaw = typeof raw === 'string' ? raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim() : JSON.stringify(raw);
  parsed = JSON.parse(cleanRaw);
} catch (e) {
  parsed = aiOutput;
  if (!parsed.action) {
    return { json: { ...ticket, ticket_id: ticket.id, ai_action: 'escalate', ai_confidence: 0, final_status: 'escalated' } };
  }
}

let action = parsed.action || 'escalate';
let confidence = Number(parsed.confidence || 0);
const messageText = (ticket.raw_message || '').toLowerCase();
const refundSignals = ['rembours', 'refund', 'argent', 'money', 'débit'].some(s => messageText.includes(s));

if (confidence < 65) action = 'escalate';
if (refundSignals && action === 'auto_reply') action = 'request_validation';

let finalStatus;
switch (action) {
  case 'auto_reply': finalStatus = 'resolved'; break;
  case 'request_validation': finalStatus = 'pending'; break;
  case 'escalate': finalStatus = 'escalated'; break;
  default: finalStatus = 'escalated';
}

return {
  json: {
    ...ticket,
    ticket_id: ticket.id,
    ai_category: parsed.category || ticket.category || 'Produit',
    ai_sub_type: parsed.sub_type || '',
    ai_confidence: confidence,
    ai_priority: parsed.priority || ticket.priority,
    ai_action: action,
    ai_customer_reply: parsed.customer_reply || '',
    ai_merchant_summary: parsed.merchant_summary || '',
    ai_reasoning: parsed.reasoning || '',
    ai_validation: parsed.validation || { needed: false },
    final_status: finalStatus
  }
};
